export function getDicaDoDia(): Dica {
  const now = new Date();
  const start = new Date(now.getFullYear(), 0, 0);
  const dayOfYear = Math.floor((now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  return dicas[(dayOfYear - 1 + dicas.length) % dicas.length];
}
